from lxml import etree

def process_soap_request(xml_data):
    # Define the DTD for validation
    dtd = etree.DTD('path/to/your/dtdfile.dtd')
    
    # Parse the XML data
    xml_tree = etree.fromstring(xml_data)
    
    # Validate the XML against the DTD
    if not dtd.validate(xml_tree):
        raise ValueError("XML does not conform to the DTD")
    
    # Find the SOAP envelope and body elements
    soap_envelope = xml_tree.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Envelope')
    soap_body = soap_envelope.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')
    
    if soap_body is None:
        raise ValueError("SOAP Body not found in the request")
    
    # Extract and return the message body
    message_body = etree.tostring(soap_body, pretty_print=True).decode('utf-8')
    return message_body

# Example usage
xml_request = """
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
    <soap:Body>
        <YourRequest>
            <!-- Your request data here -->
        </YourRequest>
    </soap:Body>
</soap:Envelope>
"""

try:
    body = process_soap_request(xml_request)
    print(body)
except Exception as e:
    print(f"Error processing SOAP request: {e}")